"""
This is the ASCII Microservice.
It takes nothing and returns an ascii image
from a database that represents each series
available for collection. returns a single, long
string.
"""

from flask import Flask, jsonify
import random

app = Flask(__name__)

labubu_ascii = f"                @@@@@@             \n              @@      @@           \n                       @           \n              @@      @@           \n                #@@@@@             \n                 ==#               \n              -#  -@-=             \n            @@-*@@:@- :=@:         \n           @@    @ @*    @+        \n          -@@  @ @-%. @@ @@#       \n          @@   @ @+@# @@ @@        \n          @@ =..   :*=. :@@@       \n         %= +.* .   .= @ :         \n       #%+..-.=%@=%:*- .:*%*@      \n      @* -@@%@@@@@@@@@@@@*=@:@     \n     %+ @@%    ....-::::+*@%@@@@   \n     @*% *=-+:-=%===  -@@@@- -@@   \n     @::@#@=  @  ==## @  +@@:@*@   \n     @+-@:=:.@@@ -=+ @@@ -@@+@%@   \n      @@-@ =  @  :@ @ @  ++%:@@    \n       @.@@: @        .=:@@@@@     \n        @+=@*%-@@@@@@@-:@ :@       \n     -@@@=*%@@@@#=+%@@@@@@@*@      \n   .@@=@%**+  -. :.-%-+@@ *@@@@@   \n   @*+:#*%@==@:=@@=*@.@ @@+=+ @@   \n   @@@@@@@:+#==%*@ @ @=@@%@.@@@@@  \n        @-+**-@-:@@-*@% @-@@       \n        @#+%#++=:*@+= @@-@@@       \n        @=: =-@#=%%==@:=: #@+      \n        @%@%==%  @+.##@@@@@@-      \n        @%@%+*@@@@ @@@% .@#@       \n        @+=-*@+*@   % =+#* @       \n        @@@##@@@@  @@@*@-@@@       \n         @@@+@@      @@@@@         \n                                   "
tama_ascii = f"  .                @.@@            \n : @  @@@@@@@@@   @@   @@          \n @*@@*:= @  - @@@@ @     @         \n @%       -@@  @##@ @     #        \n @* %@@@@@@@@@@@@@@@ @      @      \n @-+@           @+ @  @:     @%    \n+- @@  @    @   @@%%@  @@@    @@   \n#+*@@           @@%#@    @@     @  \n*=%@@  -----    @@##@     .@     @ \n-#%@@ : .     + @@@*@       @     @\n @@@@@@@@@@%@@@@@**@          @@@@ \n  @@@@@@@@@@@@@@@@@                \n    @@@ @@ @@#*@@                  \n      =%%##@#@-                    \n"
skull_ascii = f"             @@@  @@@              \n            @@      #@             \n            @        @             \n            @        @             \n             @@@=% @@              \n               @@@@                \n               @@@@                \n               @@@@                \n               @@@@                \n                @@@                \n          @@@@@@@@@@@@@@           \n       @@@@@@@@@@@@@@@=@@@@        \n      @@@@@@@@@@@@#@@@@@@@@@       \n     @@@@@%=@#*@@@#@ +.#@@@@@      \n    @@@@+@@@@@@@%*@@@@=@%:@@@@     \n    @@@%%*:%@ .:--:  @.#-@%@ @     \n   @@@ *+@@.-=#*+---@* @@*##@@     \n   @@*#+@@.--*@+@@@@%@@ @@@+@@     \n   #@#@@@#*@@@   @    @%@-@::@     \n   @@@=@-.+    :   =*: -@=@%@@     \n   @:*.@%@@- -@@+@@@*-@*@*++@@@@   \n @@@@@==-@ @@@+  * %.@+:@ #@@@@@=@ \n   -@=@=@*:     @@-   .@@@-=  @@ @ \n  @ @  #@#@@@@@- -%@@@@@@=*@ @  %@ \n @@%@@@=@# @@%@@@+++@@@ @=@@%@@@@  \n      @*@@=.:.@@ @@ =@:+-@@%@      \n   @@@@ .--+@@  @@:*++*#@ -:*@     \n   @@:@@@@@@ @@@@-@:@+=-*:@@@@@@   \n     @-+.  @@@:%-@.=@@@=-@@@@@     \n      @@@@ + @: @  *@-  @@@@@@@    \n     *@@@@@@@@@@@@@@@ @@@@@@@@     \n       %@@@@@@@@@@@@@@@@@@@@       \n       *@@@@#@@@@@@@#@@@@# @       \n      @@@+@@@*@@@ @%%#@+@@@@@      \n       @@ .*:=@%@ @@**-=..=@@      \n        @@@@@*@@@  @@@@@@@@@       \n"
goodbye_ascii = [labubu_ascii, tama_ascii, skull_ascii]

@app.route("/ascii", methods=["POST"])
def ascii_service():
    choice = random.randint(0,2)
    return jsonify({
        "ascii_art": goodbye_ascii[choice]
    })

if __name__ == "__main__":
    print("\n" + "=" * 50)
    print("Ascii Microservice is Running")
    print("http://localhost:5006")
    print("=" * 50 + "\n")

    app.run(port=5006, debug=True)
